@page "/privacy"
@using Microsoft.AspNetCore.Http
@attribute [ExcludeFromInteractiveRouting]
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (hasConsent)
{
    <div class="alert alert-success">
        <strong>✓ You have already accepted our cookie policy.</strong>
    </div>
}
else
{
    <div class="alert alert-warning">
        <strong>You have not yet accepted our cookie policy.</strong>
    </div>
}

<h2>Cookie Usage</h2>
<p>
    This site uses cookies to improve your experience. By using this site, you
    agree to our use of cookies as described in this policy.
</p>

<h2>What Cookies We Use</h2>
<ul>
    <li><strong>Essential cookies</strong> – required for basic site functionality.</li>
    <li><strong>Consent cookie</strong> – records whether you have accepted our cookie policy.</li>
</ul>

@code {
    private bool hasConsent;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            hasConsent = httpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

